import React from 'react';


function QuestionCard(params){

  const question = params.params;
  const question_id = question.id;
 
    return(
        <div id="questionCard">
         
        <div className="card">
            <h5 className="card-header">{question.titel}</h5>
            <div className="card-body">
              <h5 className="card-title">{question.subtitle}</h5>
              <p className="card-text">{question.description}</p>
              
              <div className="form-check">
                <input className="form-check-input" type="radio" {...{id:question_id+"inlineRadio1", name:question_id+"inlineRadioOptions"}} value="1"></input>
                <label className="form-check-label" for="inlineRadio1">{question.answers[0].a1}</label>
                </div>
              <div className="form-check">
                <input className="form-check-input" type="radio" {...{id:question_id+"inlineRadio2", name:question_id+"inlineRadioOptions"}} value="2"></input>
                <label className="form-check-label" for="inlineRadio2">{question.answers[0].a2} </label>
              </div>
              <div className="form-check">
                <input className="form-check-input" type="radio" {...{id:question_id+"inlineRadio3", name:question_id+"inlineRadioOptions"}} value="3"></input>
                <label className="form-check-label" for="inlineRadio3">{question.answers[0].a3}</label>
              </div>
              <div className="form-check">
                <input className="form-check-input" type="radio" {...{id:question_id+"inlineRadio4", name:question_id+"inlineRadioOptions"}} value="4"></input>
                <label className="form-check-label" for="inlineRadio4">{question.answers[0].a4}</label>
              </div>
              </div> 
            </div>
            </div>
        
      
        )
    
 
}


export default QuestionCard;
