import React from 'react';
import { getAnswerData } from './AppState';

import {
  Chart as ChartJS,
  RadialLinearScale,
  PointElement,
  LineElement,
  Filler,
  Tooltip,
  Legend,
  Scale,
} from 'chart.js';
import { Radar } from 'react-chartjs-2';

ChartJS.register(
  RadialLinearScale,
  PointElement,
  LineElement,
  Filler,
  Tooltip,
  Legend
);



const data_ans = getAnswerData();






function getRadarData() {
  var a = new Array();
  data_ans.forEach(element => {
    if(element.data.subtitle.length > 35){



      a.push([element.data.subtitle.slice(0, element.data.subtitle.indexOf(" ",15)) ,element.data.subtitle.slice(element.data.subtitle.indexOf(" ",15)) ]); 

    }else  if(element.data.subtitle.length > 20){
      a.push([element.data.subtitle.slice(0, element.data.subtitle.indexOf(" ",5)) ,element.data.subtitle.slice(element.data.subtitle.indexOf(" ",5)) ]); 

    }else{
      a.push(element.data.subtitle); 
    }
  
  })
  return a;
}

function getRadarValues() {
  var a = new Array();
  data_ans.forEach(element => {

    a.push(element.value + 1);
  })
  return a;
}


function Results(params) {

  console.log("DAta", data_ans);
  var radar_labels = getRadarData();
  var radar_values = getRadarValues();
  var radar_data = {

    labels: radar_labels,
    datasets: [
      {
        label: 'Level',
        data: radar_values,
        backgroundColor: 'rgba(255, 99, 132, 0.2)',
        borderColor: 'rgba(155, 99, 132, 0.2)',
        borderWidth: 1,
      },
    ],
  }
  return (

    <div>
      <div class="row">
        <div class="col-4">
          <div class="card">
            <h5 class="card-header">Based on your answers we recommend to take the modules:  </h5>
            <div class="card-body">
              {data_ans.length ? (
                <div>

                  {data_ans.map((module) => (
                    module.value < 2 ? (
                     
                        <div class="card">
                          <div class="card-header">
                            {module.data.subtitle}
                          </div>
                          <div class="card-body">
                            <h5 class="card-title">Placeholder</h5>
                            <p class="card-text">{module.data.description}</p>
                            <a href="#" class="btn btn-primary">Go to module page or smt</a>
                          </div>
                        </div>
                      ) : null
                  ))}
                </div>
              ) : (
                <p>
                  <i>No recommendations</i>
                </p>
              )}
            </div>
          </div>
        </div>


        <div class="col-8">
          <Radar data={radar_data} options={{
             plugins: {
              legend: {
               display:false,
                
              }
            },
            responsive: true,
            scales: {
            
              r: {
                suggestedMin: 0,
                suggestedMax: 4,
                pointLabels:{
                  font:{
                    size:10
                  ,
                  }
                },
                ticks:{
                  precision:0,
                  color: "rgba(25, 5, 255,1)",
                  font:{
                    size:15,
                  }
                },
              }
            }
          }} />

        </div>
      </div>
    </div>

  )

}



export default Results;


