import questions from "../Questions.json";
import QuestionCard from "../QuestionCard";
import Btn_NextQuestion from '../Btn_NextQuestion';
import React, { useState } from 'react';
import { Link, Navigate, redirect } from "react-router-dom";

import { setAnswer, getAnswerValue } from "../AppState";

export default function QuestionContainer () {
  const [q_number, setNumber] = useState(0);
  const [show, setShow] = React.useState(true);
  const [progress, setProgress] = React.useState(0.00);
  const [showAlert, setShowAlert] = React.useState(false);
  var nrOfQuestions = questions.questions.length;
  var btn_next =<Btn_NextQuestion onClick={()=> handle_answer()} ></Btn_NextQuestion>; 
 
  var ar_questions=[];
  questions.questions.forEach(question => {

    ar_questions.push(<QuestionCard params={question} ></QuestionCard>);

  });

 
  const handle_answer = () => {
    
    var _checked_answer = getCheckedAnswer();
  
    if(_checked_answer != -1)
    {setShowAlert(false);
      setAnswer(q_number,{value:_checked_answer, data:questions.questions[q_number]});

      setProgress(((q_number+1)/questions.questions.length)*100);
      console.log(progress);
      if(q_number < nrOfQuestions-1){
        setNumber(q_number+1);
      }else{
        setNumber(q_number+1);
        setShow(false);
      }
    }
    else{ setShowAlert(true);}
   
   }

   const getCheckedAnswer = () => {
    var a = q_number+1;
    if(document.getElementById(a+"inlineRadio1").checked){ document.getElementById(a+"inlineRadio1").checked =false; return 0;}
    else if(document.getElementById(a+"inlineRadio2").checked){document.getElementById(a+"inlineRadio2").checked =false;return 1;}
    else if(document.getElementById(a+"inlineRadio3").checked){document.getElementById(a+"inlineRadio3").checked =false;return 2;}
    else if(document.getElementById(a+"inlineRadio4").checked){document.getElementById(a+"inlineRadio4").checked =false;return 3;}
    else{return -1;}
   }
return(
  <div>
  {ar_questions[q_number]}
  <br></br>
  <div class="progress">
  <div class="progress-bar" role="progressbar"  style={{width: progress+'%'}} aria-valuenow="50" aria-valuemin="0" aria-valuemax="100"> {q_number+1} / {questions.questions.length}</div>
  
</div>
<br></br>
   {show ? btn_next: <Navigate replace to="/results"></Navigate>}
   {showAlert ? <div class="alert alert-warning" role="alert">
  Please choose an answer from the list above!
</div>:null}
 
  </div>
)
   
  
}
